export default "/* inlined from ../_variables.css */\n:host {\n  --theme-bg: hsl(0 0% 100%);\n  --theme-bd: hsl(0 0% 100% / .8);\n  --theme-bd-2: hsl(0 0% 100% / .9);\n  --theme-color: hotpink;\n  --theme-blue: hsl(188 90% 45%);\n  --theme-purple: hsl(267 100% 58%);\n\n  --theme-text_color: hsl(0 0% 10%);\n  --theme-icon_color: hsl(0 0% 20%);\n  --theme-icon_hover-bg: hsl(0 0% 95%);\n  --theme-icon_active-bg: hsl(0 0% 90%);\n\n  --layer-top: 2147483647;\n  --layer-1: 2147483646;\n  --layer-2: 2147483645;\n  --layer-3: 2147483644;\n  --layer-4: 2147483643;\n  --layer-5: 2147483642;\n\n  @media (prefers-color-scheme: dark) {\n    --theme-bg: hsl(0 0% 10%);\n    --theme-bd: hsl(0 0% 10% / .8);\n    --theme-bd-2: hsl(0 0% 10% / .9);\n\n    --theme-text_color: hsl(0 0% 80%);\n    --theme-icon_color: hsl(0 0% 60%);\n    --theme-icon_hover-bg: hsl(0 0% 15%);\n    --theme-icon_active-bg: hsl(0 0% 20%);\n  }\n}\n\n\n:host > svg {\n  position: absolute;\n  top: var(--top);\n  left: var(--left);\n  overflow: visible;\n  pointer-events: none;\n  z-index: var(--layer-3);\n}\n\n:host > svg .resize-hitarea {\n  pointer-events: auto;\n}\n\n:host > svg .resize-hitarea-east {\n  cursor: ew-resize;\n}\n\n:host > svg .resize-hitarea-southeast {\n  cursor: nwse-resize;\n}\n";
